class FixedWindowLimiter:
    def __init__(self, limit, window_seconds):
        self.limit = limit
        self.window_seconds = window_seconds
        self.windows = {}

    def allow(self, key, timestamp):
        window = timestamp // self.window_seconds
        if key not in self.windows or self.windows[key][0] != window:
            self.windows[key] = (window, 1)
            return True
        current_window, count = self.windows[key]
        new_count = count + 1
        self.windows[key] = (current_window, new_count)
        return new_count <= self.limit
